"""Low-level database driver wrapper for Meridian Analytics Platform.

Provides a thin abstraction over psycopg2, handling connection creation,
basic health checks, and resource cleanup.
"""

import logging
import time
from typing import Optional

import psycopg2
from psycopg2.extensions import connection as PgConnection

from db.config import DBConfig, default_config

logger = logging.getLogger(__name__)


class ConnectionError(Exception):
    """Raised when a database connection cannot be established."""
    pass


class Connection:
    """Wrapper around a psycopg2 connection with health-check support."""

    def __init__(self, raw_conn: PgConnection, created_at: Optional[float] = None):
        self._raw: PgConnection = raw_conn
        self.created_at: float = created_at or time.time()
        self.last_used: float = self.created_at
        self.last_health_check: float = self.created_at
        self._in_use: bool = False

    @property
    def raw(self) -> PgConnection:
        return self._raw

    @property
    def in_use(self) -> bool:
        return self._in_use

    @in_use.setter
    def in_use(self, value: bool) -> None:
        self._in_use = value
        if value:
            self.last_used = time.time()

    def health_check(self) -> bool:
        """Run a lightweight health check (SELECT 1)."""
        try:
            with self._raw.cursor() as cur:
                cur.execute("SELECT 1")
            self.last_health_check = time.time()
            return True
        except Exception as e:
            logger.warning("Health check failed: %s", e)
            return False

    def close(self) -> None:
        """Close the underlying connection."""
        try:
            self._raw.close()
        except Exception as e:
            logger.warning("Error closing connection: %s", e)

    def __repr__(self) -> str:
        status = "in_use" if self._in_use else "idle"
        return f"<Connection id={id(self._raw)} status={status}>"


def create_connection(config: Optional[DBConfig] = None) -> Connection:
    """Create a new database connection from configuration."""
    config = config or default_config
    try:
        raw_conn = psycopg2.connect(
            host=config.host,
            port=config.port,
            dbname=config.database,
            user=config.user,
            password=config.password,
            sslmode=config.ssl_mode,
        )
        raw_conn.autocommit = True
        return Connection(raw_conn)
    except psycopg2.Error as e:
        raise ConnectionError(f"Failed to connect to {config.host}:{config.port}/{config.database}: {e}") from e
